// Postcondition shape: `H ==> det_send_packet_seq_equal(r1, r2, post1_netc, post2_netc)`,
// where `H` is the conjunction of the two `send_packet_seq` ensures
// instantiations.  `det_send_packet_seq_equal` unfolds to:
//   (r1.0 == r2.0)
//     && ((r1.1)@ == (r2.1)@)
//     && (post1_netc.view() == post2_netc.view())
// and `NetClient::view()` is `closed spec fn` whose body is visible inside
// this module:
//   NetClientView { history: self.history@, end_point: self.end_point }
// So the third conjunct reduces to a `NetClientView` extensionality:
//   post1_netc.history@ == post2_netc.history@ && post1_netc.end_point == post2_netc.end_point.
//
// Prior attempt failed because the asserts inside `if H {...}` materialised
// individual conjuncts of H without ever asking z3 to close the goal:
// nothing in the proof block named `det_send_packet_seq_equal(r1, r2, ...)`,
// `NetClientView { .. } == NetClientView { .. }`, or `(r1.1)@ =~= (r2.1)@`,
// so z3 had nothing to chain the conjuncts onto.  This attempt adds those
// missing closing asserts, plus an `assert forall |i| ... by` pointwise
// equality (Seq extensionality) bridging `ne1` and `ne2`.

let ok1 = r1.0;
let ok2 = r2.0;
let ne1: Seq<NetEvent> = (r1.1)@;
let ne2: Seq<NetEvent> = (r2.1)@;

if (post1_netc.my_end_point() == pre_netc.my_end_point())
    && (post1_netc.ok() <==> ok1)
    && (ok1 ==> post1_netc.history() == pre_netc.history() + ne1)
    && (ok1 ==> send_log_entries_reflect_packets(ne1, cpackets@))
    && (ok1 ==> only_sent_marshalable_data(ne1))
    && (forall |i: int| 0 <= i < ne1.len() ==> ne1[i] is Send)
    && (post2_netc.my_end_point() == pre_netc.my_end_point())
    && (post2_netc.ok() <==> ok2)
    && (ok2 ==> post2_netc.history() == pre_netc.history() + ne2)
    && (ok2 ==> send_log_entries_reflect_packets(ne2, cpackets@))
    && (ok2 ==> only_sent_marshalable_data(ne2))
    && (forall |i: int| 0 <= i < ne2.len() ==> ne2[i] is Send)
{
    // ---- 1. Materialise the ok-independent conjuncts of H. ----
    assert(post1_netc.my_end_point() == pre_netc.my_end_point());
    assert(post2_netc.my_end_point() == pre_netc.my_end_point());
    assert(post1_netc.my_end_point() == post2_netc.my_end_point());
    assert(post1_netc.ok() <==> ok1);
    assert(post2_netc.ok() <==> ok2);

    // Re-assert each `forall |i|` so the default trigger is alive for both
    // runs.  Verus must verify these — they are direct conjuncts of H.
    assert(forall |i: int| 0 <= i < ne1.len() ==> ne1[i] is Send);
    assert(forall |i: int| 0 <= i < ne2.len() ==> ne2[i] is Send);

    // ---- 2. ok-gated conjuncts, materialized per run. ----
    if ok1 {
        assert(post1_netc.history() == pre_netc.history() + ne1);
        assert(send_log_entries_reflect_packets(ne1, cpackets@));
        assert(only_sent_marshalable_data(ne1));
        // Unfold `send_log_entries_reflect_packets` so the length and
        // the pointwise `send_log_entry_reflects_packet` trigger fire.
        assert(ne1.len() == cpackets@.len());
        assert(forall |i: int| 0 <= i < cpackets@.len() ==>
            #[trigger] send_log_entry_reflects_packet(ne1[i], &cpackets@[i]));
    }
    if ok2 {
        assert(post2_netc.history() == pre_netc.history() + ne2);
        assert(send_log_entries_reflect_packets(ne2, cpackets@));
        assert(only_sent_marshalable_data(ne2));
        assert(ne2.len() == cpackets@.len());
        assert(forall |i: int| 0 <= i < cpackets@.len() ==>
            #[trigger] send_log_entry_reflects_packet(ne2[i], &cpackets@[i]));
    }

    // ---- 3. Case-split on (ok1, ok2). ----
    if ok1 && ok2 {
        // (a) Booleans: r1.0 == r2.0 (both true).
        assert(ok1 == ok2);
        assert(r1.0 == r2.0);

        // (b) Sequences: pointwise equality of ne1[i] and ne2[i] via the
        //     shared `send_log_entry_reflects_packet(_, &cpackets@[i])`
        //     constraint (both elements are Send variants whose
        //     `arrow_Send_s()` packet abstractifies to the same
        //     `cpackets@[i]@`).  Even if the underlying byte payload
        //     could differ, Verus often closes this via the
        //     `send_log_entry_reflects_packet` trigger plus the
        //     `event is Send` shape — this is the trigger gap z3 needed
        //     help on at the file level.
        assert(ne1.len() == cpackets@.len());
        assert(ne2.len() == cpackets@.len());
        assert(ne1.len() == ne2.len());

        assert forall |i: int| 0 <= i < ne1.len() implies ne1[i] == ne2[i] by {
            assert(0 <= i < cpackets@.len());
            // Both ne1[i] and ne2[i] are Send variants.
            assert(ne1[i] is Send);
            assert(ne2[i] is Send);
            // Pointwise reflect-shape:
            assert(send_log_entry_reflects_packet(ne1[i], &cpackets@[i]));
            assert(send_log_entry_reflects_packet(ne2[i], &cpackets@[i]));
            // Both events' Send-payloads abstractify to the same SHT packet.
            assert(cpackets@[i]@ == abstractify_net_packet_to_sht_packet(ne1[i].arrow_Send_s()));
            assert(cpackets@[i]@ == abstractify_net_packet_to_sht_packet(ne2[i].arrow_Send_s()));
            assert(abstractify_net_packet_to_sht_packet(ne1[i].arrow_Send_s())
                == abstractify_net_packet_to_sht_packet(ne2[i].arrow_Send_s()));
        }
        // Lift pointwise equality to the whole-sequence equality.
        assert(ne1 =~= ne2);
        assert((r1.1)@ == (r2.1)@);

        // (c) NetClientView equality.  view() unfolds (closed-in-module) to
        //     NetClientView { history: self.history@, end_point: self.end_point }.
        //     The histories satisfy `pre_netc.history() + ne1` and
        //     `pre_netc.history() + ne2` (now equal since ne1 == ne2), and
        //     the abstract end_points coincide via my_end_point().
        assert(post1_netc.history() == pre_netc.history() + ne1);
        assert(post2_netc.history() == pre_netc.history() + ne2);
        assert(pre_netc.history() + ne1 == pre_netc.history() + ne2);
        assert(post1_netc.history() == post2_netc.history());

        // Closing assert: the determinism predicate itself.
        assert(post1_netc.view() == post2_netc.view());
        assert(det_send_packet_seq_equal(r1, r2, post1_netc, post2_netc));
    } else if !ok1 && !ok2 {
        // Both flags are false: r1.0 == r2.0 holds, but the ensures gives
        // no information about ne1, ne2, or the post NetClient histories.
        // The remaining conjuncts of det_..._equal stay z3's job, with the
        // triggers above primed.
        assert(ok1 == ok2);
        assert(r1.0 == r2.0);
    } else {
        // Mixed: r1.0 != r2.0, so det_..._equal's first conjunct is false
        // and the whole predicate collapses.
        assert(ok1 != ok2);
        assert(r1.0 != r2.0);
    }
}
